-- Create reference table for PLC error and warning codes
-- Source: Übersicht Fehler & Warnungen CB1 (EN) spreadsheet from machine manufacturer
-- 104 codes total: 91 alarms (A-prefix), 13 warnings (W-prefix)

CREATE TABLE IF NOT EXISTS plc_error_codes (
  code        VARCHAR(10) PRIMARY KEY,
  severity    VARCHAR(10) NOT NULL DEFAULT 'alarm',
  description TEXT NOT NULL,
  cause       TEXT,
  solution    TEXT,
  info        TEXT
);

ON CONFLICT (code) DO UPDATE SET
  severity    = EXCLUDED.severity,
  description = EXCLUDED.description,
  cause       = EXCLUDED.cause,
  solution    = EXCLUDED.solution,
  info        = EXCLUDED.info;
